const express = require('express');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const { Client } = require('magicbell-js/project-client');

const app = express();
const PORT = 3001;

// Environment variables
const RUN_ID = process.env.ZEALT_RUN_ID || 'default';
const MAGICBELL_EMAIL = process.env.MAGICBELL_EMAIL;
const MAGICBELL_API_KEY = process.env.MAGICBELL_API_KEY;
const MAGICBELL_SECRET_KEY = process.env.MAGICBELL_SECRET_KEY;

// Derived user info
const userEmail = `${MAGICBELL_EMAIL}+${RUN_ID}@gmail.com`;
const userExternalId = `user-${RUN_ID}`;

app.use(cors());

// GET /token - Generate and return a MagicBell User JWT
app.get('/token', (req, res) => {
  const payload = {
    email: userEmail,
    external_id: userExternalId,
  };

  const token = jwt.sign(payload, MAGICBELL_SECRET_KEY, {
    algorithm: 'HS256',
    header: {
      alg: 'HS256',
      typ: 'JWT',
    },
  });

  res.json({ token });
});

// Bootstrap: upsert user and create broadcast on startup
async function bootstrap() {
  try {
    // The ProjectClient token is base64(apiKey:apiSecret) for Bearer auth
    const projectToken = Buffer.from(`${MAGICBELL_API_KEY}:${MAGICBELL_SECRET_KEY}`).toString('base64');

    const client = new Client({
      token: projectToken,
    });

    // Upsert the user
    console.log(`Upserting user: ${userEmail} (${userExternalId})`);
    await client.users.saveUser({
      email: userEmail,
      externalId: userExternalId,
    });

    // Create a seed broadcast
    const broadcastTitle = `Welcome to MagicBell ${RUN_ID}`;
    console.log(`Creating broadcast: ${broadcastTitle}`);
    await client.broadcasts.createBroadcast({
      title: broadcastTitle,
      content: 'This is a welcome notification to get you started with MagicBell!',
      category: 'welcome',
      recipients: [
        { externalId: userExternalId },
      ],
    });

    console.log('Bootstrap completed successfully');
  } catch (error) {
    console.error('Bootstrap error:', error.message);
    if (error.response) {
      console.error('Response data:', JSON.stringify(error.response.data || error.response));
    }
  }
}

app.listen(PORT, () => {
  console.log(`Backend server running on port ${PORT}`);
  bootstrap();
});

import React, { useState, useEffect } from 'react';
import { MagicBellProvider as Provider, FloatingInbox } from '@magicbell/react';

function App() {
  const [token, setToken] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('http://localhost:3001/token')
      .then((res) => res.json())
      .then((data) => {
        setToken(data.token);
      })
      .catch((err) => {
        setError(err.message);
      });
  }, []);

  if (error) {
    return <div>Error loading token: {error}</div>;
  }

  if (!token) {
    return <div>Loading...</div>;
  }

  return (
    <Provider token={token}>
      <div style={{ padding: '20px' }}>
        <h1>MagicBell Notifications</h1>
        <p>Click the bell icon to view your notifications.</p>
      </div>
      <FloatingInbox
        placement="bottom-end"
        height={600}
        width={500}
        offset={20}
      />
    </Provider>
  );
}

export default App;
